import{_ as a,o,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"19. Casual Employment","description":"","frontmatter":{"title":"19. Casual Employment","eba":"Doctors in Training 2022-2026","topics":["employment"]},"headers":[],"relativePath":"ebas/doctors-in-training/doctor-employment/19-casual-employment.md","filePath":"ebas/doctors-in-training/doctor-employment/19-casual-employment.md"}'),r={name:"ebas/doctors-in-training/doctor-employment/19-casual-employment.md"};function s(l,e,i,p,c,m){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="_19-casual-employment" tabindex="-1">19. Casual Employment <a class="header-anchor" href="#_19-casual-employment" aria-label="Permalink to &quot;19. Casual Employment&quot;">​</a></h1><p><strong>19.1</strong> A casual means a Doctor classified as a HMO, MO or SMO and who is engaged in relieving work or work of a casual nature, but does not include a Doctor who could properly be classified as a full-time or part-time Doctor under <a href="/eba/ebas/doctors-in-training/doctor-employment/17-full-time-employment.html">clauses 17</a> and 18.</p><p><strong>19.2</strong> Subject to the minimum engagement period (or payment in lieu of), a casual Doctor’s engagement is terminable with one hour’s notice by either party. The minimum engagement for a casual Employee is two hours.</p><p><strong>19.3</strong> A casual Doctor will be paid an hourly rate equal to 1/38th of the weekly salary for the Employee’s classification plus 25%.</p><p><strong>19.4</strong> Except where expressly excluded, a casual Employee will be entitled to receive the allowances prescribed by this Agreement.</p><p><strong>19.5</strong> A casual Doctor is entitled to the following:</p><p><strong>(a)</strong> unpaid carer&#39;s leave for carer’s responsibilities (subclause 61.10);</p><p><strong>(b)</strong> unpaid family violence leave (<a href="/eba/ebas/doctors-in-training/leave/71-family-violence-leave.html">clause 71</a>);</p><p><strong>(c)</strong> unpaid compassionate leave in accordance with the NES;</p><p><strong>(d)</strong> unpaid pre-adoption leave (<a href="/eba/ebas/doctors-in-training/leave/66-pre-adoption-leave.html">clause 66</a>);</p><p><strong>(e)</strong> parental leave (<a href="/eba/ebas/doctors-in-training/leave/67-parental-leave.html">clause 67</a>) (subject to the eligibility requirements of that clause);</p><p><strong>(f)</strong> applicable penalty payments for work performed on a public holiday (<a href="/eba/ebas/doctors-in-training/leave/63-public-holidays.html">clause 63</a>);</p><p><strong>(g)</strong> payments for shift work (subclauses 37.3 and 37.5);</p><p><strong>(h)</strong> Saturdays and Sundays (subclause 37.2); and</p><p><strong>(i)</strong> overtime (<a href="/eba/ebas/doctors-in-training/hours-of-work/36-overtime.html">clause 36</a>).</p><p><strong>19.6</strong> The following provisions do not apply to casual Doctors:</p><p><strong>(a)</strong> annual leave (<a href="/eba/ebas/doctors-in-training/leave/60-annual-leave.html">clause 60</a>);</p><p><strong>(b)</strong> paid personal/carer&#39;s leave (<a href="/eba/ebas/doctors-in-training/leave/61-personal-sick-carer-s-leave.html">clause 61</a>);</p><p><strong>(c)</strong> paid compassionate leave (<a href="/eba/ebas/doctors-in-training/leave/64-compassionate-leave.html">clause 64</a>);</p><p><strong>(d)</strong> paid family violence leave (<a href="/eba/ebas/doctors-in-training/leave/71-family-violence-leave.html">clause 71</a>);</p><p><strong>(e)</strong> conference/seminar leave (<a href="/eba/ebas/doctors-in-training/education-pd/50-conference-seminar-leave.html">clause 50</a>);</p><p><strong>(f)</strong> examination leave (<a href="/eba/ebas/doctors-in-training/education-pd/49-examination-leave.html">clause 49</a>);</p><p><strong>(g)</strong> rosters (<a href="/eba/ebas/doctors-in-training/hours-of-work/35-rosters.html">clause 35</a>);</p><p><strong>(h)</strong> notice period before termination (<a href="/eba/ebas/doctors-in-training/doctor-employment/29-termination-of-employment.html">clause 29</a>);</p><p><strong>(i)</strong> period of employment (<a href="/eba/ebas/doctors-in-training/doctor-employment/21-period-of-employment.html">clause 21</a>);</p><p><strong>(j)</strong> flexible working arrangements (other than Doctors prescribed at subclause 15.2(b)) (<a href="/eba/ebas/doctors-in-training/consultation-disputes/15-flexible-working-arrangements.html">clause 15</a>);</p><p><strong>(k)</strong> payment for public holiday penalties where the Doctor doesn’t perform work on that day (<a href="/eba/ebas/doctors-in-training/leave/63-public-holidays.html">clause 63</a>);</p><p><strong>(l)</strong> child care costs reimbursement (<a href="/eba/ebas/doctors-in-training/allowances/57-child-care-costs-reimbursement-out-of-hours-work.html">clause 57</a>); and</p><p><strong>(m)</strong> community service leave (under the Act).</p><p>Plain language terms: casual.</p>',30)])])}const d=a(r,[["render",s]]);export{u as __pageData,d as default};
